class Solution {
public:
    string longestPalindrome(string s) {
        if (s.empty()) return "";
        int n = s.length();
        int start = 0, maxLen = 0;
        for (int i = 0; i < n; i++) {
            // Check odd-length palindromes
            int l1 = i, r1 = i;
            while (l1 >= 0 && r1 < n && s[l1] == s[r1]) {
                l1--;
                r1++;
            }
            int len1 = r1 - l1 - 1;
            if (len1 > maxLen) {
                maxLen = len1;
                start = l1 + 1;
            }

            // Check even-length palindromes
            int l2 = i, r2 = i + 1;
            while (l2 >= 0 && r2 < n && s[l2] == s[r2]) {
                l2--;
                r2++;
            }
            int len2 = r2 - l2 - 1;
            if (len2 > maxLen) {
                maxLen = len2;
                start = l2 + 1;
            }
        }
        return s.substr(start, maxLen);
    }
};

